const resp = $input.first()?.json ?? {};
const messages = Array.isArray(resp.messages) ? resp.messages : [];
if (!messages.length) {
  return [{
    json: {
      id: null,
      threadId: null,
      historyId: resp.historyId ?? null,
      resultSizeEstimate: resp.resultSizeEstimate ?? 0,
      hasMessages: false,
      totalMessages: 0,
      isEmpty: true,
    },
  }];
}

return messages.map((m) => ({
  json: {
    id: m.id,
    threadId: m.threadId,
    historyId: resp.historyId ?? null,
    resultSizeEstimate: resp.resultSizeEstimate ?? null,
    hasMessages: true,
    totalMessages: messages.length,
    isEmpty: false,
  },
}));

const item = $input.first()?.json ?? {};

if (!item.payload && !item.headers && !item.threadId) {
  return [{
    json: {
      ok: true,
      count: 0,
      data: [],
      items: [],
      messages: [],
      netflixCode: null,
      codeSource: null,
      message: 'Tidak ada email Netflix hari ini',
    },
  }];
}

const headers = Array.isArray(item.payload?.headers) ? item.payload.headers : [];
const headerMap = Object.fromEntries(
  headers
    .filter((h) => h && h.name)
    .map((h) => [String(h.name).toLowerCase(), h.value ?? null]),
);

const subject = String(headerMap.subject ?? '');
const from = String(headerMap.from ?? '');
const snippet = String(item.snippet ?? '');
const bodyText = String(snippet);
const searchText = `${subject}\n${bodyText}`;

const hintRegex = /(?:verification code|security code|sign(?:-|\s)?in code|login code|one[-\s]?time code|authentication code|use this code|your code is|code is)[\s\S]{0,120}?(\d{6})/i;
const fallbackRegex = /\b(\d{6})\b/;
const match = searchText.match(hintRegex) || searchText.match(fallbackRegex);
const netflixCode = match ? match[1] : null;
const codeSource = match ? (match[0] === match[1] ? 'fallback:6-digit' : 'hint') : null;

return [{
  json: {
    messageId: item.id ?? null,
    threadId: item.threadId ?? null,
    labelIds: item.labelIds ?? [],
    internalDate: item.internalDate ?? null,
    receivedAt: item.internalDate ? new Date(Number(item.internalDate)).toISOString() : null,
    from: headerMap.from ?? null,
    to: headerMap.to ?? null,
    cc: headerMap.cc ?? null,
    bcc: headerMap.bcc ?? null,
    replyTo: headerMap['reply-to'] ?? null,
    subject: headerMap.subject ?? null,
    date: headerMap.date ?? null,
    fromDomain: (from.match(/@([A-Z0-9.-]+)\b/i)?.[1] || '').toLowerCase(),
    snippet: item.snippet ?? null,
    bodyText,
    netflixCode,
    codeSource,
    codeCandidates: netflixCode ? [{ source: codeSource, code: netflixCode }] : [],
    isNetflixCandidate: /netflix/i.test(`${from} ${subject} ${snippet}`),
  },
}];

const resp = $input.first()?.json ?? {};
const messages = Array.isArray(resp.messages) ? resp.messages : [];
const ids = messages.map((m) => m.id).filter(Boolean);
if (!ids.length) return [];
return [{ json: { ids, count: ids.length } }];
